/**
 * Tests for ErrorHandler
 */

import { jest } from '@jest/globals';
import ErrorHandler from '../src/utils/ErrorHandler.js';

describe('ErrorHandler', () => {
  let errorHandler;
  let mockLogger;

  beforeEach(() => {
    mockLogger = {
      error: jest.fn(),
      warn: jest.fn(),
      info: jest.fn(),
      debug: jest.fn()
    };
    errorHandler = new ErrorHandler(mockLogger);
  });

  describe('categorize', () => {
    it('should categorize API errors', () => {
      const error = new Error('API authentication failed');
      error.name = 'APIError';
      
      const type = errorHandler.categorize(error);
      expect(type).toBe('API');
    });

    it('should categorize rate limit errors', () => {
      const error = new Error('Rate limit exceeded');
      
      const type = errorHandler.categorize(error);
      expect(type).toBe('API');
    });

    it('should categorize file system errors', () => {
      const error = new Error('File not found');
      error.code = 'ENOENT';
      
      const type = errorHandler.categorize(error);
      expect(type).toBe('FILE_SYSTEM');
    });

    it('should categorize permission errors', () => {
      const error = new Error('Permission denied');
      error.code = 'EACCES';
      
      const type = errorHandler.categorize(error);
      expect(type).toBe('FILE_SYSTEM');
    });

    it('should categorize user input errors', () => {
      const error = new Error('Invalid input');
      error.name = 'ValidationError';
      
      const type = errorHandler.categorize(error);
      expect(type).toBe('USER_INPUT');
    });

    it('should categorize network errors', () => {
      const error = new Error('Connection refused');
      error.code = 'ECONNREFUSED';
      
      const type = errorHandler.categorize(error);
      expect(type).toBe('NETWORK');
    });

    it('should categorize system errors', () => {
      const error = new Error('Out of memory');
      error.code = 'ENOMEM';
      
      const type = errorHandler.categorize(error);
      expect(type).toBe('SYSTEM');
    });

    it('should categorize unknown errors', () => {
      const error = new Error('Something went wrong');
      
      const type = errorHandler.categorize(error);
      expect(type).toBe('UNKNOWN');
    });
  });

  describe('getUserMessage', () => {
    it('should return user-friendly message for authentication errors', () => {
      const error = new Error('authentication failed');
      const message = errorHandler.getUserMessage('API', error);
      
      expect(message).toContain('API key');
    });

    it('should return user-friendly message for rate limit errors', () => {
      const error = new Error('rate limit exceeded');
      const message = errorHandler.getUserMessage('API', error);
      
      expect(message).toContain('rate limit');
    });

    it('should return user-friendly message for file not found', () => {
      const error = new Error('ENOENT: no such file');
      error.code = 'ENOENT';
      const message = errorHandler.getUserMessage('FILE_SYSTEM', error);
      
      expect(message).toContain('does not exist');
    });

    it('should return user-friendly message for permission denied', () => {
      const error = new Error('EACCES: permission denied');
      error.code = 'EACCES';
      const message = errorHandler.getUserMessage('FILE_SYSTEM', error);
      
      expect(message).toContain('Permission denied');
    });

    it('should return user-friendly message for disk full', () => {
      const error = new Error('ENOSPC: no space left');
      error.code = 'ENOSPC';
      const message = errorHandler.getUserMessage('FILE_SYSTEM', error);
      
      expect(message).toContain('disk is full');
    });

    it('should return user-friendly message for network errors', () => {
      const error = new Error('Connection refused');
      error.code = 'ECONNREFUSED';
      const message = errorHandler.getUserMessage('NETWORK', error);
      
      expect(message).toContain('Connection refused');
    });
  });

  describe('isRecoverable', () => {
    it('should mark rate limit errors as recoverable', () => {
      const error = new Error('rate limit exceeded');
      const recoverable = errorHandler.isRecoverable('API', error);
      
      expect(recoverable).toBe(true);
    });

    it('should mark timeout errors as recoverable', () => {
      const error = new Error('timeout');
      error.code = 'ETIMEDOUT';
      const recoverable = errorHandler.isRecoverable('API', error);
      
      expect(recoverable).toBe(true);
    });

    it('should mark file not found as recoverable', () => {
      const error = new Error('file not found');
      error.code = 'ENOENT';
      const recoverable = errorHandler.isRecoverable('FILE_SYSTEM', error);
      
      expect(recoverable).toBe(true);
    });

    it('should mark user input errors as recoverable', () => {
      const error = new Error('invalid input');
      const recoverable = errorHandler.isRecoverable('USER_INPUT', error);
      
      expect(recoverable).toBe(true);
    });

    it('should mark out of memory as not recoverable', () => {
      const error = new Error('out of memory');
      error.code = 'ENOMEM';
      const recoverable = errorHandler.isRecoverable('SYSTEM', error);
      
      expect(recoverable).toBe(false);
    });

    it('should mark disk full as not recoverable', () => {
      const error = new Error('no space left');
      error.code = 'ENOSPC';
      const recoverable = errorHandler.isRecoverable('FILE_SYSTEM', error);
      
      expect(recoverable).toBe(false);
    });
  });

  describe('isCritical', () => {
    it('should mark out of memory as critical', () => {
      const error = new Error('out of memory');
      error.code = 'ENOMEM';
      const critical = errorHandler.isCritical('SYSTEM', error);
      
      expect(critical).toBe(true);
    });

    it('should mark disk full as critical', () => {
      const error = new Error('no space left');
      error.code = 'ENOSPC';
      const critical = errorHandler.isCritical('FILE_SYSTEM', error);
      
      expect(critical).toBe(true);
    });

    it('should mark system errors as critical', () => {
      const error = new Error('system error');
      const critical = errorHandler.isCritical('SYSTEM', error);
      
      expect(critical).toBe(true);
    });

    it('should not mark API errors as critical', () => {
      const error = new Error('api error');
      const critical = errorHandler.isCritical('API', error);
      
      expect(critical).toBe(false);
    });
  });

  describe('getRecoveryStrategy', () => {
    it('should return retry strategy for rate limit errors', () => {
      const error = new Error('rate limit exceeded');
      const strategy = errorHandler.getRecoveryStrategy('API', error, {});
      
      expect(strategy).toEqual({
        action: 'retry',
        delay: 5000,
        maxRetries: 3,
        backoff: 'exponential'
      });
    });

    it('should return retry strategy for timeout errors', () => {
      const error = new Error('timeout');
      error.code = 'ETIMEDOUT';
      const strategy = errorHandler.getRecoveryStrategy('API', error, {});
      
      expect(strategy).toEqual({
        action: 'retry',
        delay: 2000,
        maxRetries: 3,
        backoff: 'exponential'
      });
    });

    it('should return prompt strategy for file not found', () => {
      const error = new Error('file not found');
      error.code = 'ENOENT';
      const strategy = errorHandler.getRecoveryStrategy('FILE_SYSTEM', error, {});
      
      expect(strategy).toEqual({
        action: 'prompt',
        message: 'Would you like to provide a different file path?'
      });
    });

    it('should return prompt strategy for user input errors', () => {
      const error = new Error('invalid input');
      const strategy = errorHandler.getRecoveryStrategy('USER_INPUT', error, {});
      
      expect(strategy).toEqual({
        action: 'prompt',
        message: 'Please provide valid input.'
      });
    });

    it('should return retry strategy for network errors', () => {
      const error = new Error('connection refused');
      const strategy = errorHandler.getRecoveryStrategy('NETWORK', error, {});
      
      expect(strategy).toEqual({
        action: 'retry',
        delay: 2000,
        maxRetries: 3,
        backoff: 'exponential'
      });
    });
  });

  describe('handle', () => {
    it('should handle error and return complete error info', () => {
      const error = new Error('rate limit exceeded');
      const context = { operation: 'sendMessage' };
      
      const result = errorHandler.handle(error, context);
      
      expect(result).toHaveProperty('type');
      expect(result).toHaveProperty('message');
      expect(result).toHaveProperty('recoverable');
      expect(result).toHaveProperty('critical');
      expect(result).toHaveProperty('originalError');
      expect(result).toHaveProperty('recovery');
      
      expect(result.type).toBe('API');
      expect(result.recoverable).toBe(true);
      expect(result.critical).toBe(false);
      expect(mockLogger.error).toHaveBeenCalled();
    });

    it('should handle error without logger', () => {
      const errorHandlerNoLogger = new ErrorHandler();
      const error = new Error('test error');
      
      const result = errorHandlerNoLogger.handle(error);
      
      expect(result).toHaveProperty('type');
      expect(result).toHaveProperty('message');
    });
  });

  describe('retryWithBackoff', () => {
    it('should retry with exponential backoff', async () => {
      let attempts = 0;
      const fn = jest.fn(async () => {
        attempts++;
        if (attempts < 3) {
          throw new Error('temporary error');
        }
        return 'success';
      });

      const result = await errorHandler.retryWithBackoff(fn, {
        delay: 10,
        maxRetries: 3,
        backoff: 'exponential'
      });

      expect(result).toBe('success');
      expect(fn).toHaveBeenCalledTimes(3);
    });

    it('should retry with linear backoff', async () => {
      let attempts = 0;
      const fn = jest.fn(async () => {
        attempts++;
        if (attempts < 2) {
          throw new Error('temporary error');
        }
        return 'success';
      });

      const result = await errorHandler.retryWithBackoff(fn, {
        delay: 10,
        maxRetries: 3,
        backoff: 'linear'
      });

      expect(result).toBe('success');
      expect(fn).toHaveBeenCalledTimes(2);
    });

    it('should throw error after max retries', async () => {
      const fn = jest.fn(async () => {
        throw new Error('persistent error');
      });

      await expect(
        errorHandler.retryWithBackoff(fn, {
          delay: 10,
          maxRetries: 3,
          backoff: 'exponential'
        })
      ).rejects.toThrow('persistent error');

      expect(fn).toHaveBeenCalledTimes(3);
    });
  });

  describe('extractPath', () => {
    it('should extract path from error message', () => {
      const error = new Error("ENOENT: no such file or directory, open '/path/to/file.txt'");
      const path = errorHandler.extractPath(error);
      
      expect(path).toBe('/path/to/file.txt');
    });

    it('should return empty string if no path found', () => {
      const error = new Error('generic error');
      const path = errorHandler.extractPath(error);
      
      expect(path).toBe('');
    });
  });
});
